sys_ws_operation.operation_script:
(function process(request, response) {
  var utils = new AlationUtils();

  var body    = utils.readJsonOnce(request) || {};

  // Locate by sys_id OR number OR externalIncidentId
  var sysId  = String(body.sys_id || '').trim();
  var number = String(body.number || '').trim();
  var extId  = String(body.externalIncidentId || '').trim();

  if (!sysId && !number && !extId) {
    return utils.error(response, 400, 'sys_id or number or externalIncidentId required');
  }

  // Find existing incident (we still validate existence to preserve behavior)
  var inc = new GlideRecord('incident');
  var found = false;

  if (sysId && inc.get(sysId)) {
    found = true;
  } else if (number) {
    inc.addQuery('number', number);
    inc.setLimit(1);
    inc.query();
    if (inc.next()) found = true;
  } else if (extId) {
    inc.addQuery('correlation_id', extId);
    inc.setLimit(1);
    inc.query();
    if (inc.next()) found = true;
  }

  if (!found) return utils.error(response, 404, 'incident not found');

  // Prevent outbound notify loop (your existing mechanism)
  gs.getSession().putClientData('update_from_alation', 'true');

  // Correlation id is the stable key for transform coalesce
  // Prefer the incident’s existing correlation_id, else extId (if provided)
  var corr = String(inc.getValue('correlation_id') || '').trim();
  if (!corr && extId) corr = extId;

  if (!corr) {
    // If you require correlation_id for all Alation incidents, enforce it
    return utils.error(response, 400, 'externalIncidentId / correlation_id missing for update');
  }

  // -------------------------
  // Stage the inbound update
  // -------------------------
  var requestId = gs.generateGUID();

  var STAGING_TABLE = 'x_alati_dpm_serv_0_alation_inbound_incident_staging';

  var stageRec = new GlideRecord(STAGING_TABLE);
  stageRec.initialize();

  stageRec.u_external_incident_id = corr;

  // Map update fields into staging (only those you allow)
  // short_description supports alias "summary"
  if (body.short_description != null) stageRec.u_summary = String(body.short_description);
  else if (body.summary != null)      stageRec.u_summary = String(body.summary);
  else                               stageRec.u_summary = String(inc.getValue('short_description') || '');

  if (body.description != null) stageRec.u_description = String(body.description);
  else                          stageRec.u_description = String(inc.getValue('description') || '');

  // Assignee: accept sys_id or username; store raw input (transform resolves)
  var assigneeStr = '';
  if (body.assignee_id != null) assigneeStr = String(body.assignee_id).trim();
  else if (body.assigned_to != null) assigneeStr = String(body.assigned_to).trim();
  stageRec.u_assigned_to = assigneeStr;

  // Traceability fields
  stageRec.u_raw_payload       = String(body);
  stageRec.u_request_id        = requestId;
  stageRec.u_received_at       = new GlideDateTime();
  stageRec.u_source            = 'alation';
  stageRec.u_processing_status = 'pending';
  stageRec.u_processing_error  = '';

  var stageId = stageRec.insert();
  if (!stageId) return utils.error(response, 500, 'failed to stage update request');

  // -------------------------
  // Create sys_import_set
  // -------------------------
  var importSetRec = new GlideRecord('sys_import_set');
  importSetRec.initialize();
  importSetRec.short_description = 'Alation inbound update request ' + requestId;
  importSetRec.table_name = STAGING_TABLE;

  var importSetId = importSetRec.insert();
  if (!importSetId) {
    stageRec.u_processing_status = 'error';
    stageRec.u_processing_error  = 'failed to create sys_import_set';
    stageRec.update();
    return utils.error(response, 500, 'failed to create import set');
  }

  // Link staged row to import set (requires sys_import_set field on staging table)
  stageRec.sys_import_set = importSetId;
  stageRec.update();

  if (!importSetRec.get(importSetId)) {
    stageRec.u_processing_status = 'error';
    stageRec.u_processing_error  = 'import set not retrievable';
    stageRec.update();
    return utils.error(response, 500, 'import set not retrievable');
  }

  // -------------------------
  // Run Transform Map (SYNC)
  // -------------------------
  var mapSysId = String(gs.getProperty('x_alati_dpm_serv_0.transform_map_incident_sys_id') || '').trim();
  if (!mapSysId) {
    stageRec.u_processing_status = 'error';
    stageRec.u_processing_error  = 'transform map sys_id property not configured';
    stageRec.update();
    return utils.error(response, 500, 'transform map not configured');
  }

  try {
    var transformer = new GlideImportSetTransformer();
    transformer.setMapID(mapSysId);
    transformer.setSyncImport(true);
    transformer.transformAllMaps(importSetRec);

    stageRec.u_processing_status = 'processed';
    stageRec.u_processing_error  = '';
    stageRec.update();

  } catch (e) {
    stageRec.u_processing_status = 'error';
    stageRec.u_processing_error  = String(e);
    stageRec.update();
    return utils.error(response, 500, 'transform failed: ' + e);
  }

  // -------------------------
  // Fetch updated incident
  // -------------------------
  var out = new GlideRecord('incident');
  out.addQuery('correlation_id', corr);
  out.setLimit(1);
  out.query();
  if (!out.next()) return utils.error(response, 500, 'incident not found after transform');

    // Build assignee object safely
  var assigneeObj = null;
  var assigneeId  = String(out.getValue('assigned_to') || '').trim();
  if (assigneeId) {
    var u = new GlideRecord('sys_user');
    if (u.get(assigneeId)) {
      assigneeObj = {
        account_id:   String(u.getUniqueValue()),
        display_name: String(u.getValue('name') || out.getDisplayValue('assigned_to') || ''),
        user_name:    String(u.getValue('user_name') || ''),
        email:        String(u.getValue('email') || '')
      };
    } else {
      assigneeObj = {
        account_id:   String(assigneeId),
        display_name: String(out.getDisplayValue('assigned_to') || '')
      };
    }
  }

  return utils.ok(response, 200, {
    sys_id: String(inc.sys_id),
    number: String(inc.number),
    short_description: String(inc.short_description || ''),
    description: String(inc.description || ''),
    state: String(inc.state),
    state_label: inc.getDisplayValue('state'),
    assignee: assigneeObj,

    url: utils.incidentUrl(String(inc.sys_id))
  });

})(request, response);
